1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	type Item = {
12	  type: string;
13	  cursed?: boolean;
14	  enchantment?: number;
15	  material?: string;
16	};
17	type Customer = { years: number };
18	type Step = { type: string; items: Item[]; customer?: Customer };
19	
20	const BLOCK_OF_3_PRICE = 60;
21	
22	const COMPONENT_TYPES = ["rune", "moonstone"];
23	
24	function countByType(items: Item[]): Record<string, number> {
25	  const counts: Record<string, number> = {};
26	  for (const item of items) {
27	    counts[item.type] = (counts[item.type] ?? 0) + 1;
28	  }
29	  return counts;
30	}
31	
32	function priceForType(type: string, count: number): number {
33	  if (COMPONENT_TYPES.includes(type) && count === 3) {
34	    return BLOCK_OF_3_PRICE;
35	  }
36	  return count * BASE_PREMIUM_BY_TYPE[type];
37	}
38	
39	function isHighlyEnchanted(item: Item): boolean {
40	  return (item.enchantment ?? 0) >= 5;
41	}
42	
43	function hasItemModifier(item: Item): boolean {
44	  return Boolean(item.cursed) || isHighlyEnchanted(item);
45	}
46	
47	const CURSE_SURCHARGE = 0.5;
48	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
49	
50	function itemSurcharge(item: Item): number {
51	  const base = BASE_PREMIUM_BY_TYPE[item.type];
52	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE : 0;
53	  const enchantmentSurcharge = isHighlyEnchanted(item)
54	    ? base * HIGH_ENCHANTMENT_SURCHARGE
55	    : 0;
56	  return curseSurcharge + enchantmentSurcharge;
57	}
58	
59	function modifiedItemsBasePremium(items: Item[]): number {
60	  return items
61	    .filter(hasItemModifier)
62	    .reduce((total, item) => total + BASE_PREMIUM_BY_TYPE[item.type], 0);
63	}
64	
65	function plainPremium(items: Item[]): number {
66	  const counts = countByType(items.filter((item) => !hasItemModifier(item)));
67	  return Object.entries(counts).reduce(
68	    (total, [type, count]) => total + priceForType(type, count),
69	    0,
70	  );
71	}
72	
73	function basePremium(items: Item[]): number {
74	  return modifiedItemsBasePremium(items) + plainPremium(items);
75	}
76	
77	function surchargePremium(items: Item[]): number {
78	  return items.reduce((total, item) => total + itemSurcharge(item), 0);
79	}
80	
81	const LOYALTY_DISCOUNT = 0.2;
82	const LOYALTY_MIN_YEARS = 2;
83	const FIRST_INSURANCE_SURCHARGE = 0.1;
84	const FOLLOW_UP_DISCOUNT = 0.15;
85	
86	function isLoyal(customer: Customer): boolean {
87	  return customer.years >= LOYALTY_MIN_YEARS;
88	}
89	
90	function policyPremium(step: Step, isFollowUp: boolean): number {
91	  const base = basePremium(step.items);
92	  const surcharges = surchargePremium(step.items);
93	  if (step.customer === undefined) {
94	    return base + surcharges;
95	  }
96	  const loyaltyDiscount = isLoyal(step.customer) ? LOYALTY_DISCOUNT : 0;
97	  const followUpDiscount = isFollowUp ? FOLLOW_UP_DISCOUNT : 0;
98	  const netModifierRate =
99	    FIRST_INSURANCE_SURCHARGE - loyaltyDiscount - followUpDiscount;
100	  return base + surcharges + base * netModifierRate;
101	}
102	
103	function roundUpInFavor(amount: number): number {
104	  return Math.ceil(amount);
105	}
106	
107	export function runScenario(steps: Step[]): unknown[] {
108	  return steps.map((step, index) => {
109	    const isFollowUp = steps
110	      .slice(0, index)
111	      .some((prior) => prior.type === "quote");
112	    return {
113	      premium: roundUpInFavor(PROCESSING_FEE + policyPremium(step, isFollowUp)),
114	    };
115	  });
116	}
