it("should pay 400 G for a regular sword with 500 G damage (full minus 100 deductible)", () => {
  const results = runScenario([
    { type: "quote", items: [{ type: "sword" }] },
    {
      type: "claim",
      policy: 0,
      incident: {
        cause: "fire",
        damages: [{ itemType: "sword", amount: 500 }],
      },
    },
  ]);
  expect(results).toEqual([
    { premium: 105 },
    { payout: 400, remainingCap: 1600 },
  ]);
});

type Customer = { years: number };
type Damage = { itemType: string; amount: number };
type Incident = { cause: string; damages: Damage[] };
type Step = {
  type: string;
  items?: Item[];
  customer?: Customer;
  policy?: number;
  incident?: Incident;
};

const items = step.items ?? [];
const base = basePremium(items);
const surcharges = surchargePremium(items);
